INSERT INTO topics (id, title, subject, syllabus_tag, content, readability_score) VALUES
('polity-001', 'Fundamental Rights', 'polity', 'GS2-POL-L01', '{"definitions": ["Fundamental Rights are constitutionally guaranteed protections against state action, enshrined in Part III (Articles 12-35) of the Indian Constitution. They protect liberty, equality, freedom of speech, and dignity."], "key_concepts": [{"title": "Article 14 - Right to Equality", "body": "Guarantees equality before the law and equal protection of laws. It prohibits arbitrary classification and discrimination."}, {"title": "Article 21 - Right to Life", "body": "No person shall be deprived of life or personal liberty except according to procedure established by law."}], "pyqs": [{"year": 2023, "question": "Which article guarantees equality before law?", "answer": "Article 14"}], "common_traps": ["Article 14 protects against arbitrariness too, not just discrimination."], "summary": "Fundamental Rights form the bedrock of constitutional democracy.", "source_url": "", "hi": {"definitions": ["मौलिक अधिकार संविधान में भाग III (अनुच्छेद 12-35) में निहित संवैधानिक गारंटी वाले संरक्षण हैं।"], "key_concepts": [{"title": "अनुच्छेद 14 - समानता का अधिकार", "body": "कानून के समक्ष समानता और कानूनों के समान संरक्षण की गारंटी देता है।"}, {"title": "अनुच्छेद 21 - जीवन का अधिकार", "body": "किसी भी व्यक्ति को जीवन या व्यक्तिगत स्वतंत्रता से वंचित नहीं किया जाएगा, सिवाय कानूनी प्रक्रिया के।"}], "common_traps": ["अनुच्छेद 14 केवल भेदभाव से नहीं, बल्कि मनमानापन से भी सुरक्षा देता है।"], "summary": "मौलिक अधिकार संवैधानिक लोकतंत्र की नींव हैं।"}}', 75),
('polity-002', 'Directive Principles of State Policy', 'polity', 'GS2-POL-L02', '{"definitions": ["DPSPs are guidelines for governance in Part IV (Articles 36-51). They are non-justiciable but fundamental to good governance."], "key_concepts": [{"title": "Article 39 - Livelihood and Equal Pay", "body": "The State shall direct policy towards securing adequate means of livelihood and equal pay for equal work."}, {"title": "Article 44 - Uniform Civil Code", "body": "The State shall endeavour to secure a Uniform Civil Code throughout India."}], "pyqs": [{"year": 2022, "question": "Which Part contains DPSP?", "answer": "Part IV"}], "common_traps": ["DPSPs are non-justiciable but courts may consider them while interpreting laws."], "summary": "DPSPs guide the state toward social and economic justice.", "source_url": "", "hi": {"definitions": ["राज्य के नीति निर्देशक सिद्धांत भाग IV (अनुच्छेद 36-51) में शासन के लिए दिशानिर्देश हैं।"], "key_concepts": [{"title": "अनुच्छेद 39 - जीविका और समान वेतन", "body": "राज्य अपनी नीति को पर्याप्त जीविका और समान कार्य के लिए समान वेतन सुनिश्चित करने की दिशा में निर्देशित करेगा।"}, {"title": "अनुच्छेद 44 - समान नागरिक संहिता", "body": "राज्य पूरे भारत में समान नागरिक संहिता सुनिश्चित करने का प्रयास करेगा।"}], "common_traps": ["नीति निर्देशक सिद्धांत अनुलंघनीय नहीं हैं, लेकिन न्यायालय उन्हें विचार में ले सकता है।"], "summary": "नीति निर्देशक सिद्धांत राज्य को सामाजिक और आर्थिक न्याय की ओर मार्गदर्शन करते हैं।"}}', 75),
('polity-003', 'Parliament', 'polity', 'GS2-POL-L03', '{"definitions": ["Parliament is the supreme legislative body of India, consisting of the President, Rajya Sabha, and Lok Sabha."], "key_concepts": [{"title": "Article 79 - Constitution of Parliament", "body": "Parliament consists of the President and two Houses: Rajya Sabha and Lok Sabha."}, {"title": "Article 105 - Privileges", "body": "Members enjoy freedom of speech and immunity from court proceedings for anything said in Parliament."}], "pyqs": [{"year": 2021, "question": "Which article deals with privileges of Parliament?", "answer": "Article 105"}], "common_traps": ["Rajya Sabha is not a permanent body; one-third of members retire every two years."], "summary": "Parliament exercises legislative supremacy and financial control.", "source_url": "", "hi": {"definitions": ["संसद भारत का सर्वोच्च विधायी निकाय है, जिसमें राष्ट्रपति, राज्य सभा और लोक सभा शामिल हैं।"], "key_concepts": [{"title": "अनुच्छेद 79 - संसद का गठन", "body": "संसद राष्ट्रपति और दो सदनों: राज्य सभा और लोक सभा से मिलकर बनी है।"}, {"title": "अनुच्छेद 105 - विशेषाधिकार", "body": "सदस्यों को संसद में कहे गए किसी भी बात के लिए अभिव्यक्ति की स्वतंत्रता और न्यायालय कार्यवाही से छूट का आनंद मिलता है।"}], "common_traps": ["राज्य सभा स्थायी निकाय नहीं है; इसके एक तिहाई सदस्य हर दो साल में सेवानिवृत्त होते हैं।"], "summary": "संसद विधायी सर्वोच्चता और वित्तीय नियंत्रण का प्रयोग करती है।"}}', 75),
('polity-004', 'Judiciary', 'polity', 'GS2-POL-L04', '{"definitions": ["The Indian Judiciary is an independent and integrated system headed by the Supreme Court. It is the guardian of the Constitution."], "key_concepts": [{"title": "Article 124 - Supreme Court", "body": "The Supreme Court consists of a Chief Justice and up to 33 judges, appointed by the President on the collegium's advice."}, {"title": "Article 226 - High Court Writs", "body": "High Courts can issue writs for enforcement of fundamental rights and for any other purpose."}], "pyqs": [{"year": 2020, "question": "Which article gives writ jurisdiction to High Courts?", "answer": "Article 226"}], "common_traps": ["High Courts have wider writ jurisdiction than Supreme Court under Article 32."], "summary": "An independent judiciary is essential for constitutional democracy.", "source_url": "", "hi": {"definitions": ["भारतीय न्यायपालिका उच्चतम न्यायालय के नेतृत्व वाली एक स्वतंत्र और एकीकृत प्रणाली है। यह संविधान का संरक्षक है।"], "key_concepts": [{"title": "अनुच्छेद 124 - उच्चतम न्यायालय", "body": "उच्चतम न्यायालय में एक मुख्य न्यायाधीश और 33 अन्य न्यायाधीश होते हैं, जिन्हें राष्ट्रपति कोलेजियम की सलाह पर नियुक्त करता है।"}, {"title": "अनुच्छेद 226 - उच्च न्यायालय के लेख", "body": "उच्च न्यायालय मौलिक अधिकारों के प्रवर्तन और किसी अन्य उद्देश्य के लिए लेख जारी कर सकते हैं।"}], "common_traps": ["उच्च न्यायालयों का लेख अधिकार क्षेत्र अनुच्छेद 32 के तहत उच्चतम न्यायालय से व्यापक है।"], "summary": "स्वतंत्र न्यायपालिका संवैधानिक लोकतंत्र के लिए आवश्यक है।"}}', 75),
('polity-005', 'Federalism', 'polity', 'GS2-POL-L05', '{"definitions": ["Indian federalism distributes powers between Union and States. It is quasi-federal with a strong Centre."], "key_concepts": [{"title": "Article 245 - Territorial Extent", "body": "Parliament may make laws for the whole or any part of India; State legislatures for the whole or any part of the State."}, {"title": "Article 356 - President's Rule", "body": "If state government cannot function constitutionally, President's Rule may be imposed."}], "pyqs": [{"year": 2019, "question": "Which article provides for President's Rule in a State?", "answer": "Article 356"}], "common_traps": ["Article 356 was frequently misused before the S.R. Bommai judgment laid down strict guidelines."], "summary": "Indian federalism balances unity with regional diversity.", "source_url": "", "hi": {"definitions": ["भारतीय संघवाद केंद्र और राज्यों के बीच शक्तियों का वितरण करता है। यह एक मजबूत केंद्र के साथ अर्ध-संघात्मक है।"], "key_concepts": [{"title": "अनुच्छेद 245 - क्षेत्रीय विस्तार", "body": "संसद पूरे भारत या किसी भी हिस्से के लिए कानून बना सकती है; राज्य विधायिकाएं पूरे राज्य या किसी भी हिस्से के लिए कानून बना सकती हैं।"}, {"title": "अनुच्छेद 356 - राष्ट्रपति शासन", "body": "यदि राज्य सरकार संवैधानिक रूप से कार्य नहीं कर सकती, तो राष्ट्रपति शासन लगाया जा सकता है।"}], "common_traps": ["अनुच्छेद 356 का अक्सर दुरुपयोग किया गया था, जब तक एस.आर. बोम्मई निर्णय ने सख्त दिशानिर्देश निर्धारित नहीं किए।"], "summary": "भारतीय संघवाद एकता को क्षेत्रीय विविधता के साथ संतुलित करता है।"}}', 75),
