INSERT INTO astra_scripts (topic, subject, script, status, language) VALUES
('Fundamental Rights', 'polity', '[{"timestamp":0,"speaker_text":"Welcome to Astra Stream. Today we explore Fundamental Rights under Part III of the Indian Constitution.","visual_hint":"Title card","key_concept":"Fundamental Rights"},{"timestamp":20,"speaker_text":"Article 14 guarantees equality before the law and equal protection of laws to all persons within India.","visual_hint":"Article 14 text overlay","key_concept":"Equality"},{"timestamp":45,"speaker_text":"Article 21 protects life and personal liberty. It has been interpreted to include dignity, privacy, and livelihood.","visual_hint":"Article 21 diagram","key_concept":"Right to Life"},{"timestamp":70,"speaker_text":"Articles 25-28 secure freedom of religion, allowing every person to profess, practice, and propagate any faith.","visual_hint":"Religious symbols","key_concept":"Religious Freedom"},{"timestamp":95,"speaker_text":"Fundamental Rights are not absolute. Reasonable restrictions can be imposed under Articles 19(2) to 19(6).","visual_hint":"Balance scale","key_concept":"Reasonable Restrictions"},{"timestamp":120,"speaker_text":"Thank you for watching. Practice MCQs on Fundamental Rights to reinforce your understanding.","visual_hint":"Quiz prompt","key_concept":"Revision"}]', 'rendered', 'en'),
('Parliament', 'polity', '[{"timestamp":0,"speaker_text":"Welcome to Astra Stream. Today we study the Parliament of India.","visual_hint":"Title card","key_concept":"Parliament"},{"timestamp":20,"speaker_text":"Article 79 establishes Parliament consisting of the President, Rajya Sabha, and Lok Sabha.","visual_hint":"Parliament diagram","key_concept":"Articles 79"},{"timestamp":45,"speaker_text":"Lok Sabha is the directly elected lower House. Its term is five years unless dissolved earlier.","visual_hint":"Lok Sabha chamber","key_concept":"Lok Sabha"},{"timestamp":70,"speaker_text":"Rajya Sabha represents the states. One-third of its members retire every two years.","visual_hint":"Rajya Sabha chamber","key_concept":"Rajya Sabha"},{"timestamp":95,"speaker_text":"Parliamentary privileges under Article 105 ensure freedom of speech within the Houses.","visual_hint":"Privileges list","key_concept":"Privileges"},{"timestamp":120,"speaker_text":"Thank you for watching. Test your knowledge with practice questions.","visual_hint":"Quiz prompt","key_concept":"Revision"}]', 'rendered', 'en'),
('Federalism', 'polity', '[{"timestamp":0,"speaker_text":"Welcome to Astra Stream. Today we examine Indian Federalism.","visual_hint":"Title card","key_concept":"Federalism"},{"timestamp":20,"speaker_text":"India is a quasi-federal state with a strong Centre. Dr. Ambedkar described it as both unitary and federal.","visual_hint":"Federal structure","key_concept":"Quasi-Federal"},{"timestamp":45,"speaker_text":"The Seventh Schedule distributes powers into Union List, State List, and Concurrent List.","visual_hint":"Three lists","key_concept":"Seventh Schedule"},{"timestamp":70,"speaker_text":"Article 356 allows President's Rule if a state government cannot function constitutionally.","visual_hint":"Article 356 text","key_concept":"President''s Rule"},{"timestamp":95,"speaker_text":"Article 248 and the residuary powers vest in the Union Parliament, reinforcing central authority.","visual_hint":"Residuary powers","key_concept":"Article 248"},{"timestamp":120,"speaker_text":"Thank you for watching. Strengthen your understanding with quizzes on Federalism.","visual_hint":"Quiz prompt","key_concept":"Revision"}]', 'rendered', 'en'),
('Indian National Movement', 'history', '[{"timestamp":0,"speaker_text":"Welcome to Astra Stream. Today we journey through the Indian National Movement.","visual_hint":"Title card","key_concept":"National Movement"},{"timestamp":20,"speaker_text":"The 1857 Revolt marked the transition from East India Company rule to direct Crown administration.","visual_hint":"1857 map","key_concept":"1857 Revolt"},{"timestamp":45,"speaker_text":"The Indian National Congress was founded in 1885. Early leaders sought administrative reforms within British rule.","visual_hint":"Congress logo","key_concept":"INC Formation"},{"timestamp":70,"speaker_text":"Gandhi returned in 1915 and transformed the movement into a mass struggle through non-violent resistance.","visual_hint":"Gandhi imagery","key_concept":"Gandhian Era"},{"timestamp":95,"speaker_text":"The Quit India Movement of 1942 unified Indians across class and caste, demanding immediate independence.","visual_hint":"Quit India poster","key_concept":"Quit India"},{"timestamp":120,"speaker_text":"Thank you for watching. Revise with topic-wise MCQs on the National Movement.","visual_hint":"Quiz prompt","key_concept":"Revision"}]', 'rendered', 'en'),
('Constitutional Amendments', 'polity', '[{"timestamp":0,"speaker_text":"Welcome to Astra Stream. Today we discuss Constitutional Amendments in India.","visual_hint":"Title card","key_concept":"Amendments"},{"timestamp":20,"speaker_text":"Article 368 provides the procedure for amending the Constitution. Some amendments require only a special majority.","visual_hint":"Article 368 overlay","key_concept":"Article 368"},{"timestamp":45,"speaker_text":"The Kesavananda Bharati case established the Basic Structure doctrine, limiting Parliament''s amending power.","visual_hint":"Court building","key_concept":"Basic Structure"},{"timestamp":70,"speaker_text":"The 42nd Amendment of 1976 is called a Mini-Constitution due to its sweeping changes.","visual_hint":"42nd Amendment text","key_concept":"42nd Amendment"},{"timestamp":95,"speaker_text":"Judicial review remains the guardian of constitutional supremacy against arbitrary amendments.","visual_hint":"Scales of justice","key_concept":"Judicial Review"},{"timestamp":120,"speaker_text":"Thank you for watching. Practice MCQs on Constitutional Amendments.","visual_hint":"Quiz prompt","key_concept":"Revision"}]', 'rendered', 'en'),
('Indian Economy', 'economy', '[{"timestamp":0,"speaker_text":"Welcome to Astra Stream. Today we survey the Indian Economy.","visual_hint":"Title card","key_concept":"Indian Economy"},{"timestamp":20,"speaker_text":"India is a mixed economy. Agriculture contributes around 15 percent of GDP but employs over 40 percent of workers.","visual_hint":"GDP pie chart","key_concept":"Agriculture"},{"timestamp":45,"speaker_text":"Services dominate GDP, driven by IT and business process outsourcing sectors globally.","visual_hint":"Services graph","key_concept":"Services Sector"},{"timestamp":70,"speaker_text":"Key reforms include GST implementation, insolvency code, and labor code consolidation.","visual_hint":"Reform timeline","key_concept":"Economic Reforms"},{"timestamp":95,"speaker_text":"Inclusive growth remains the challenge: bridging rural-urban divide and generating quality employment.","visual_hint":"Growth chart","key_concept":"Inclusive Growth"},{"timestamp":120,"speaker_text":"Thank you for watching. Test your knowledge with economy MCQs.","visual_hint":"Quiz prompt","key_concept":"Revision"}]', 'rendered', 'en'),
('Environment and Ecology', 'environment', '[{"timestamp":0,"speaker_text":"Welcome to Astra Stream. Today we explore Environment and Ecology for UPSC.","visual_hint":"Title card","key_concept":"Environment"},{"timestamp":20,"speaker_text":"Biodiversity includes genetic, species, and ecosystem diversity. India is a megadiverse country.","visual_hint":"Biodiversity graphic","key_concept":"Biodiversity"},{"timestamp":45,"speaker_text":"Climate change impacts India through extreme weather, sea level rise, and agricultural shifts.","visual_hint":"Climate map","key_concept":"Climate Change"},{"timestamp":70,"speaker_text":"National Action Plan on Climate Change has eight missions including solar and sustainable agriculture.","visual_hint":"NAPCC chart","key_concept":"NAPCC"},{"timestamp":95,"speaker_text":"The Paris Agreement and India''s net-zero by 2070 commitment shape environmental governance.","visual_hint":"Net zero timeline","key_concept":"Net Zero"},{"timestamp":120,"speaker_text":"Thank you for watching. Practice environment MCQs to boost your score.","visual_hint":"Quiz prompt","key_concept":"Revision"}]', 'rendered', 'en'),
('International Relations', 'international-relations', '[{"timestamp":0,"speaker_text":"Welcome to Astra Stream. Today we navigate India''s International Relations.","visual_hint":"Title card","key_concept":"IR"},{"timestamp":20,"speaker_text":"India follows a strategic autonomy policy, balancing partnerships with the US, Russia, and neighbors.","visual_hint":"World map","key_concept":"Strategic Autonomy"},{"timestamp":45,"speaker_text":"The Act East Policy deepens engagement with ASEAN and the Indo-Pacific region.","visual_hint":"ASEAN flags","key_concept":"Act East"},{"timestamp":70,"speaker_text":"Border disputes with China and Pakistan remain unresolved, driving defense and diplomatic priorities.","visual_hint":"Border map","key_concept":"Border Disputes"},{"timestamp":95,"speaker_text":"India''s role in the Quad and SCO reflects its growing influence in global geopolitics.","visual_hint":"Quad logo","key_concept":"Quad"},{"timestamp":120,"speaker_text":"Thank you for watching. Revise with IR-focused MCQs.","visual_hint":"Quiz prompt","key_concept":"Revision"}]', 'rendered', 'en'),
('Science & Technology', 'science-technology', '[{"timestamp":0,"speaker_text":"Welcome to Astra Stream. Today we discuss Science and Technology for UPSC.","visual_hint":"Title card","key_concept":"S&T"},{"timestamp":20,"speaker_text":"ISRO missions like Chandrayaan and Gaganyaan position India as a space power with indigenous capabilities.","visual_hint":"Rocket launch","key_concept":"ISRO"},{"timestamp":45,"speaker_text":"Artificial Intelligence and quantum computing are emerging domains with strategic and economic implications.","visual_hint":"AI neural network","key_concept":"AI & Quantum"},{"timestamp":70,"speaker_text":"Biotechnology advances in vaccines and gene therapy have public health and ethical dimensions.","visual_hint":"DNA helix","key_concept":"Biotech"},{"timestamp":95,"speaker_text":"Cybersecurity is critical as digital infrastructure expands and threats become more sophisticated.","visual_hint":"Cyber lock","key_concept":"Cybersecurity"},{"timestamp":120,"speaker_text":"Thank you for watching. Practice S&T MCQs to stay updated.","visual_hint":"Quiz prompt","key_concept":"Revision"}]', 'rendered', 'en'),
('Ethics & Aptitude', 'ethics-aptitude', '[{"timestamp":0,"speaker_text":"Welcome to Astra Stream. Today we explore Ethics, Integrity, and Aptitude for GS Paper 4.","visual_hint":"Title card","key_concept":"Ethics"},{"timestamp":20,"speaker_text":"Ethics in governance demands integrity, accountability, transparency, and compassion in public service.","visual_hint":"Values list","key_concept":"Governance Ethics"},{"timestamp":45,"speaker_text":"Aristotle''s virtue ethics, Kant''s duty-based ethics, and Bentham''s utilitarianism shape moral reasoning.","visual_hint":"Philosophers","key_concept":"Moral Philosophies"},{"timestamp":70,"speaker_text":"Emotional intelligence in administration builds trust and enables empathetic decision-making.","visual_hint":"EQ chart","key_concept":"Emotional Intelligence"},{"timestamp":95,"speaker_text":"Case studies linking theory to real administrative dilemmas are the core of GS4 preparation.","visual_hint":"Case study","key_concept":"Case Studies"},{"timestamp":120,"speaker_text":"Thank you for watching. Hone your skills with ethics case practice questions.","visual_hint":"Quiz prompt","key_concept":"Revision"}]', 'rendered', 'en');
